transformation.script:
const order = payload.order;
const visit = payload.visit;
const patient = payload.patient;

// ── Patient Type: OP → opd, IP → ipd ────────────────────────────────────
const patientTypeMap = { 'OP': 'opd', 'IP': 'ipd', 'EMERGENCY': 'emergency', 'DAY CARE': 'day care' };
const patientType = patientTypeMap[visit.typeName] || visit.typeName.toLowerCase();

// ── Patient Category: derive from isVIP flag ─────────────────────────────
const patientCategory = patient.isVIP ? 'VIP' : 'Gen';

// ── Order Date: strip time portion, keep YYYY-MM-DD only ─────────────────
const orderDate = (order.orderDate || '').split(' ')[0];

// ── HISLabCode: set to entityRID string ──────────────────────────────────
// The PATHKIND_LAB_CODE lookup (configured below) will translate this
// entityRID → Pathkind-assigned lab code before delivery.
const HISLabCode = String(payload.entityRID);

// ── Build PatientTestLists from labTests array ────────────────────────────
const patientTestLists = (order.labTests || []).map(function(test) {
  return { HISTestCode: test.serviceCode };
});

// ── Core Request Body (Mandatory Fields) ─────────────────────────────────
const body = {
  HISClientCode: 'REPLACE_WITH_PATHKIND_CLIENT_CODE',
  HISLabCode: HISLabCode,
  HISOrderId: order.orderId,
  UHIDNO: patient.mrn.documentNumber,
  IPDNO_or_OPID_No: visit.id.value,
  Patient_Type: patientType,
  Patient_Category: patientCategory,
  Title: payload.patientTitle || '',
  Patient_Name: patient.fullName,
  Gender: visit.gender.name,
  Patient_Mobile_No: patient.phone,
  Doctor_Name: visit.consultingDoctorName,
  Ref_Dr_Code: order.orderingDoctorCode || '',
  Order_DateTime: orderDate,
  PatientTestLists: patientTestLists
};

// ── Optional Fields (only added to body if present) ───────────────────────
if (payload.patientABHAId) body.AABHA_ID = payload.patientABHAId;
if (visit.speciality && visit.speciality.name) body.Ward_Category = visit.speciality.name;
if (patient.email) body.Patient_Email = patient.email;
if (order.orderSponsor) body.Order_Sponsor = order.orderSponsor;

// ── DOB Resolution (three-level fallback) ────────────────────────────────
// 1. patientDOBISO at root level (ISO format, preferred)
// 2. patient.dob nested (DD/MM/YYYY — converted to ISO)
// 3. patientAgeInYears as last resort
if (payload.patientDOBISO && payload.patientDOBISO !== '') {
  body.Patient_Dob = payload.patientDOBISO;
} else if (patient.dob && patient.dob !== '') {
  const parts = patient.dob.split('/');
  body.Patient_Dob = parts[2] + '-' + parts[1] + '-' + parts[0];
} else if (visit.patientAgeInYears !== undefined && visit.patientAgeInYears !== null) {
  body.A_Age = String(visit.patientAgeInYears);
}

return body;

